var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"말도 안 돼요!","JPN":"そんな！","ENG":"No way!","TWN":"不可能吧！"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"제가 실장님을 이용한다뇨? 심지어 그 말을 부사장님이 하셨다고요?","JPN":"私が室長を利用する？　しかも、副社長がそんなことを言ったんですか？","ENG":"Me? Using the chief? And that's what the Vice President said?","TWN":"我利用室長？副總真的這麼說嗎？"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"설마 이것도 입사 테스트인 건가…?","JPN":"もしかして、これも入社テストなのかな……？","ENG":"Is this part of the employment test...?","TWN":"難道這也是試用期考試的一部分嗎?"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"단순 추측이지만 부사장도 오해한 게 아닐까 싶네.","JPN":"単なる推測にすぎないが、副社長も誤解したのではないかと思う。","ENG":"My guess is that the Vice President also misunderstood the situation.","TWN":"雖然只是猜測，但副總可能也誤會了吧。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"이러니 저러니 해도 범죄 이력은 화려하니 말이야, 하하하!","JPN":"なんと言っても、すごい犯罪歴なのだからな。ハハハ！","ENG":"On paper, you do have a colorful criminal record! Ha ha ha!","TWN":"不管怎麼說，你的犯罪記錄可真是輝煌啊，哈哈哈！"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"저도 억울하다고요. 이렇게 될 줄 누가 알았나?","JPN":"私も納得いかないんですよ。こうなるなんてまったく知らなかったし。","ENG":"It sucks to be wrongfully accused. Who knew things would end up like this?","TWN":"我也覺得很冤枉啊，誰知道會變成這樣？"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"솔직히 어떡하면 좋을지 모르겠다고요.","JPN":"正直どうしたらいいかわかりません。","ENG":"Honestly, I don't know what to do.","TWN":"說實話，我真不知道該怎麼辦……"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"요호호-!","JPN":"ヨホホー！","ENG":"Yo ho ho!","TWN":"喔呵呵—！"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"그건 아니야, 유피. 우리 해적단의 목표는 처음부터 하나였다구?","JPN":"それは違うよ、ユピ。私たち海賊団の目標は、最初から一つだったんだ！","ENG":"No, Yuppie. The Sigma Pirates only had one goal from the start.","TWN":"那可不對，悠菲。我們海盜團的目標從一開始就只有一個。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"네. 오해는 나중에 풀어도 그만이지만 보물은 하나니까요.","JPN":"はい。誤解を解くのは後からでもいいのですが、お宝はたった一つです。","ENG":"That's right. Misunderstandings can be resolved later, but the treasure out there is only one.","TWN":"是。誤會可以以後再解開，但寶藏只有一個。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"여차하면 보물을 판 돈으로 보석금을 내버리죠.","JPN":"いざとなったら、お宝を売ったお金で保釈金を払いましょう。","ENG":"If push comes to shove, we can pay bail with the money we get after selling the treasure.","TWN":"情況不妙的話，就用賣掉寶物的錢來交保釋金吧。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"좋아, 조타기를 돌리도록, 유피 선원. 크레데레 선원! 마침내 다음 행선지가 정해졌다!","JPN":"よし、舵を回せ。ユピ船員、クレデレ船員！　ついに次の行き先が決まった！","ENG":"Great. Turn the wheel, Yuppie. Credere! Our next destination has been set!","TWN":"好，轉動舵輪，悠菲船員。克蕾妲莉船員！我們終於確定了下一個目的地！"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"세계 최대의 휴양지. 블루로즈 섬.","JPN":"世界最大のリゾート地。ブルーローズ島。","ENG":"The best vacation spot in the world. Blue Rose Island.","TWN":"世界上最大的度假勝地。藍玫瑰島。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"그곳이야말로 보물이 잠들어 있는 최종 목적지야!","JPN":"そこが、お宝が眠ってる最後の目的地に違いない！","ENG":"That's where the treasure lies!","TWN":"那裡才是埋著寶藏的最終目的地！"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"또 섬인 건 제쳐두고, 그럼 밀항이라도 해야 할까요?","JPN":"また島なのは置いといて、それなら密航でもするべきなんですか？","ENG":"Besides it being another island, do we have to smuggle ourselves in there?","TWN":"撇開又是島嶼的問題，我們現在是要偷渡過去嗎？"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"저랑 크레데레가 범죄자 신분인 이상, 섬까지 갈 방법이 없잖아요.","JPN":"私とクレデレが犯罪者である以上、島まで行く方法がないじゃないですか。","ENG":"Since Credere and I are criminals, we don't have a way to get to the island.","TWN":"既然我和克蕾妲莉是罪犯身份，就沒有辦法去島上了。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"걱정 마. 그거라면 친구들이 있으니까!","JPN":"心配しないで。それなら、友だちがいるし！","ENG":"Don't worry about that. I have some friends who can help out!","TWN":"別擔心，有朋友們在呢！"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"친구들?","JPN":"友だち？","ENG":"\\"Friends\\"?","TWN":"朋友們？"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"응. 잠시 확성기 좀 빌릴게?","JPN":"うん。ちょっと拡声器を借りるね？","ENG":"Yup. I'm going to borrow your megaphone.","TWN":"嗯。我要借用一下你的擴音器喔？"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"하하! 이 타이탄도 힘을 빌려주겠네!","JPN":"ハハ！　このタイタンも力を貸そう！","ENG":"Ha ha! I will offer my assistance as well!","TWN":"哈哈！我這泰坦也會借你力量的！"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"내 음성 출력 장치라면 먼 곳까지도 소리가 퍼져 나가겠지!","JPN":"吾輩の音声出力装置なら、遠いところまで音が響くだろう！","ENG":"My sound output module should be able to help carry your voice.","TWN":"如果用我的音訊輸出裝置，聲音應該能傳得很遠吧！"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"응. 고마워, 할아버지!","JPN":"うん。ありがとう、おじいちゃん！","ENG":"Okay. Thank you, Grandpa!","TWN":"嗯，謝謝你，爺爺！"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"그럼…….","JPN":"それじゃあ……","ENG":"Then...","TWN":"那麼……"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"실장님? 입만 뻥긋거리면서 뭐 하시는 거예요?","JPN":"室長？　口だけ動かして何してるんですか？","ENG":"Chief? Why are you mouthing something without any sound?","TWN":"室長？你光張著嘴幹嘛呢？"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"듣지 못한다고 소리가 없는 건 아닙니다, 유피.","JPN":"聞こえないからって音が出てないわけではありません、ユピ。","ENG":"You may not be able to hear it, but that does not mean she's not making any noise.","TWN":"聽不見並不代表沒有聲音，悠菲。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"수평선 방향을 보세요.","JPN":"水平線の方向を見てください。","ENG":"Look toward the horizon.","TWN":"你看地平線的方向。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};